const url = req.query.url || '/';
// Leading '/' whose next char is neither '/' nor '\\' (a browser normalizes
// '/\\' to '//', making it protocol-relative and off-site).
if (!/^\/[^/\\]/.test(url)) return res.redirect('/');
res.redirect(url);

String url = request.getParameter("url");
if (url == null || !url.startsWith("/") || url.startsWith("//") || url.startsWith("/\\")) url = "/";
response.sendRedirect(url);

next := r.URL.Query().Get("next")
// Same-site paths only: a leading "/" that is not "//" or "/\\" (a browser
// treats "/\\" as "//", i.e. protocol-relative and off-site).
if !strings.HasPrefix(next, "/") || strings.HasPrefix(next, "//") || strings.HasPrefix(next, "/\\") {
    next = "/"
